1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	type Item = { type: string };
13	type Step = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
15	
16	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const policyBaseOf = (items: Item[]): number =>
19	  items.reduce((sum, item) => sum + basePremiumOf(item), 0);
20	
21	const quotePremium = (items: Item[]): number => {
22	  const policyBase = policyBaseOf(items);
23	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
24	  return policyBase + firstInsuranceSurcharge + PROCESSING_FEE;
25	};
26	
27	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
28	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
29	  return { results };
30	};
